return items.map(item => {
  const payload = item.json;
  if (!payload.body) {
    return { json: { error: 'Invalid payload structure' } };
  }

  const body = payload.body;
  const channel = body.channel_type;

  let normalized = {
    botId: body.bot_id || null,
    channel: channel || null,
    conversationId: body.conversation_id || null,
    threadId: body.external_thread_id || null,
    user: {
      id: null,
      name: null,
      username: null
    },
    message: {
      id: null,
      text: null,
      type: body.message_type || null,
      timestamp: null
    },
    raw: body.raw || null
  };

  if (channel === 'telegram') {
    normalized.user.id = body.user?.external_id || body.raw?.message?.from?.id || null;
    normalized.user.name = body.user?.name || `${body.raw?.message?.from?.first_name || ''} ${body.raw?.message?.from?.last_name || ''}`.trim();
    normalized.user.username = body.user?.username || body.raw?.message?.from?.username || null;
    normalized.message.id = body.raw?.message?.message_id || null;
    normalized.message.text = body.raw?.message?.text || body.text || null;
    normalized.message.timestamp = body.raw?.message?.date || null;
  }

  if (channel === 'whatsapp') {
    normalized.user.id = body.user?.external_id || body.user?.wa_id || body.raw?.message?.from || null;
    normalized.user.name = body.user?.name || body.user?.profile?.name || body.raw?.contact?.profile?.name || null;
    normalized.user.username = null;
    normalized.message.id = body.wa_message_id || body.raw?.message?.id || null;
    normalized.message.text = body.raw?.message?.text?.body || body.text || null;
    normalized.message.timestamp = body.raw?.message?.timestamp || null;
  }

  return { json: normalized };
});

const payload = $('Normalize Payload').first().json;
const config = $('Fetch Bot Config').first().json;
// Get templates from the intent-specific fetch node
let templates = [];
try {
  const allItems = $input.all();
  templates = (allItems[0]?.json?.templates) || [];
} catch(e) { templates = []; }

// Fisher-Yates shuffle
function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

// Group by category, shuffle, take max 2 per category
let templates_xml = 'Tidak ada template khusus. Gunakan gaya bahasa natural.';
if (templates.length > 0) {
  const MAX_PER_CAT = 2;
  const groups = {};
  for (const t of templates) {
    const cat = t.category || 'general';
    if (!groups[cat]) groups[cat] = [];
    groups[cat].push(t);
  }
  const sampled = [];
  for (const cat of Object.keys(groups)) {
    const shuffled = shuffle(groups[cat]);
    sampled.push(...shuffled.slice(0, MAX_PER_CAT));
  }
  templates_xml = sampled.map(t => `<TEMPLATE_ITEM name="${t.name}" category="${t.category || 'general'}">
${t.content}
</TEMPLATE_ITEM>`).join('\n\n');
}

return [{
  json: {
    conversation_id: payload.conversationId,
    bot_id: payload.botId,
    user_message: payload.message.text,
    channel_type: payload.channel,
    user_name: payload.user.name || '',
    user_id: payload.user.id || payload.conversationId,
    system_prompt: config.system_prompt || 'You are a helpful customer service assistant.',
    bot_name: config.name || 'AI Assistant',
    templates_xml
  }
}];

const raw = $input.first().json;
const ctx = $('Prepare Context').first().json;
const messages = raw.messages || [];
const lines = [];

for (const m of messages) {
  if (m.human) lines.push(`User: ${m.human}`);
  if (m.ai) lines.push(`Assistant: ${m.ai}`);
}

return [{
  json: {
    history: lines.join('\n'),
    user_message: ctx.user_message,
    conversation_id: ctx.conversation_id,
    bot_id: ctx.bot_id,
    user_id: ctx.user_id,
    user_name: ctx.user_name,
    channel_type: ctx.channel_type
  }
}];

const raw = $input.first().json.text || $input.first().json.response?.text || '';
const match = raw.match(/\{[\s\S]*\}/);

let parsed;
try {
  parsed = JSON.parse(match ? match[0] : raw);
} catch {
  parsed = {
    intent: 'faq',
    rag_search_query: $('Format History').first().json.user_message,
    kb_type: 'faq',
    reply_direct: ''
  };
}

const validTypes = ['faq', 'policy', 'product_info', 'troubleshooting', 'internal_guideline'];
if (!validTypes.includes(parsed.kb_type)) {
  parsed.kb_type = 'faq';
}

return [{
  json: {
    ...parsed,
    history: $('Format History').first().json.history,
    user_message: $('Format History').first().json.user_message,
    conversation_id: $('Format History').first().json.conversation_id,
    bot_id: $('Format History').first().json.bot_id,
    user_id: $('Format History').first().json.user_id,
    user_name: $('Format History').first().json.user_name
  }
}];

return items.map((item) => {
    let content = String(item.json.output || item.json.response || item.json.reply_direct || '');

    // 1) Remove thinking/analysis blocks
    content = content
      .replace(/<thinking[\s\S]*?<\/thinking>/gi, '')
      .replace(/<analysis[\s\S]*?<\/analysis>/gi, '')
      .replace(/<reasoning[\s\S]*?<\/reasoning>/gi, '');

    // 2) Remove remaining HTML/XML tags
    content = content.replace(/<\/?[^>]+>/g, '');

    // 3) Clean excess whitespace
    content = content.replace(/\n{3,}/g, '\n\n').trim();

    // 4) Fallback if empty
    if (!content) {
      content = 'Maaf Kak, saya sedang mengalami kendala teknis. Mohon coba lagi ya 🙏';
    }

    item.json.content = content;
    return item;
});

