const payload = $('Normalize Payload').first().json;
const config = $('Fetch Bot Config').first().json;

// Try to read message history to detect new vs returning contact
let history = [];
try {
  history = $('Fetch History').first().json?.messages || [];
} catch(e) { history = []; }

const now = Date.now();
const isNew = history.length === 0;
const lastTs = history.length > 0
  ? new Date(history.at(-1).created_at).getTime()
  : 0;
const gapHours = lastTs > 0 ? (now - lastTs) / 3600000 : 9999;
const isReturning = !isNew && gapHours > 24;

// Forced intent — skip LLM Classifier
let forcedIntent = null;
if (isNew)       forcedIntent = 'engagement.greeting_new';
if (isReturning) forcedIntent = 'engagement.greeting_return';

return [{ json: { isNew, isReturning, gapHours: Math.round(gapHours), forcedIntent } }];

const status = $('Check Contact Status').first().json;
const forced = status.forcedIntent;

let classified = forced;
if (!forced) {
  try {
    classified = ($('Intent Classifier').first().json.text || '').trim().toLowerCase();
  } catch(e) { classified = ''; }
}

const validIntents = [
  'engagement.greeting_new','engagement.greeting_return','engagement.time_inquiry',
  'discovery.program_detail','discovery.schedule_location','discovery.tutor_profile','discovery.curriculum',
  'evaluation.pricing_inquiry','evaluation.objection_price','evaluation.objection_compare',
  'evaluation.objection_risk','evaluation.objection_authority','evaluation.objection_urgency',
  'conversion.soft','conversion.transaction','conversion.confirm',
  'retention.complaint_service','retention.complaint_refund','retention.progress_inquiry','retention.reschedule'
];

const intent = validIntents.includes(classified) ? classified : 'discovery.program_detail';
const wasForced = !!forced;

return [{ json: { intent, wasForced } }];
